const handleUpdate = async (status: 'APPROVED' | 'REJECTED', comment?: string) => {
    if (!inspection) return
    setLoading(true)
    const label = status === 'APPROVED' ? '승인' : '반려'
    try {
        const result = await updateInspection(inspection.id, { status, comment })
        if (!result.success) {
            toast.error(result.error ?? `${label} 중 오류가 발생했습니다`)
            return
        }
        toast.success(`${label}되었습니다`)
        setRejectComment('')
        setRejectMode(false)
        onOpenChange(false)
        router.refresh()
    } catch (e) {
        console.error('handleUpdate error:', e)
        toast.error(`${label} 중 오류가 발생했습니다`)
    } finally {
        setLoading(false)
    }
}

